import type { EmergencyProtocol } from "./types";

export const pediatricEmergencyProtocols: EmergencyProtocol[] = [
  {
    id: "pcr-pediatrica-emergencia",
    title: "PCR Pediátrica (PALS)",
    categoryId: "pediatric-emergency",
    sections: [
      { id: "intro", title: "Introdução", content: "A parada cardiorrespiratória (PCR) pediátrica difere fundamentalmente da adulta: na maioria das vezes é secundária à insuficiência respiratória ou choque (hipóxia), e não a arritmias primárias.\n\nPor isso, a prevenção (reconhecimento precoce de sinais de deterioração) e o manejo agressivo da via aérea e ventilação são as chaves para a sobrevida. O algoritmo segue as diretrizes PALS (Pediatric Advanced Life Support) da AHA." },
      { id: "def", title: "Definição", content: "Cessação da atividade mecânica cardíaca efetiva em paciente pediátrico (0-18 anos).\n\nRitmos de PCR:\n• Não-chocáveis (mais comuns em pediatria — 80-85%):\n  — Assistolia\n  — AESP (atividade elétrica sem pulso)\n• Chocáveis (15-20%):\n  — FV (fibrilação ventricular)\n  — TVSP (taquicardia ventricular sem pulso)\n\nFaixas etárias:\n• Neonato: 0-28 dias\n• Lactente: 29 dias a 1 ano\n• Criança: 1-12 anos (puberdade)\n• Adolescente: > 12 anos (protocolo adulto)" },
      { id: "screening", title: "Rastreamento e Identificação", content: "Reconhecimento da deterioração (ANTES da PCR):\n\nInsuficiência respiratória:\n• Taquipneia para idade\n• Tiragem (subcostal, intercostal, fúrcula)\n• Batimento de asa nasal\n• Gemência (lactentes)\n• Head bobbing\n• SpO2 < 90%\n\nChoque compensado:\n• Taquicardia para idade\n• Perfusão periférica lenta (TEC > 3s)\n• Pulsos periféricos fracos\n• Extremidades frias\n• PA NORMAL (compensação)\n\nChoque descompensado:\n• Hipotensão (PAS < 70 + 2×idade para > 1 ano)\n• Alteração do nível de consciência\n• Diurese < 1 mL/kg/h\n\nFC normal por idade: RN 120-160, lactente 100-150, 2-5a 80-140, 6-12a 70-120, >12a 60-100\nPA sistólica mínima: 60 (RN), 70 (1m-1a), 70+2×idade (1-10a), 90 (>10a)" },
      { id: "etiology", title: "Etiologia", content: "Causas de PCR pediátrica (diferente do adulto!):\n\nRESPIRATÓRIAS (mais comuns):\n• Obstrução de via aérea (OVACE, crupe, epiglotite)\n• Bronquiolite/asma grave\n• Pneumonia\n• Afogamento\n• Aspiração de corpo estranho\n\nCARDIOVASCULARES:\n• Choque séptico\n• Choque hipovolêmico (desidratação, hemorragia)\n• Cardiopatia congênita\n• Miocardite\n• Arritmias (QT longo, WPW)\n\n5H e 5T (causas reversíveis):\n• Hipovolemia (mais comum em ped!), Hipóxia, H+ (acidose), Hipo/Hipercalemia, Hipotermia\n• Tensão (pneumotórax), Tamponamento, Toxinas, Trombose pulmonar, Trombose coronária\n\nNEONATAL:\n• Asfixia perinatal\n• Prematuridade\n• Malformações congênitas\n• Sepse neonatal" },
      { id: "clinical", title: "Apresentação Clínica", content: "Identificação da PCR pediátrica:\n• Irresponsivo (não responde a estímulos)\n• Sem respiração ou gasping\n• Sem pulso (checar em < 10 segundos):\n  — Lactente: pulso braquial ou femoral\n  — Criança: pulso carotídeo ou femoral\n• FC < 60 bpm COM sinais de má perfusão = tratar como PCR!\n\nSinais de morte iminente:\n• Bradicardia < 60 bpm em criança (sinal TARDIO de hipóxia)\n• Respiração agônica (gasping)\n• Cianose central\n• Hipotonia" },
      { id: "diagnosis", title: "Diagnóstico", content: "Diagnóstico clínico imediato:\n1. Irresponsivo\n2. Sem respiração efetiva\n3. Sem pulso em 10 segundos\n4. Conectar monitor/desfibrilador → identificar ritmo\n\nMonitorização:\n• ECG contínuo\n• SpO2\n• ETCO2 (capnografia — indicador de qualidade de RCP)\n  — ETCO2 > 10-15 mmHg: RCP adequada\n  — ETCO2 < 10 mmHg: melhorar compressões\n  — Aumento súbito de ETCO2: possível RCE\n\nExames durante RCP:\n• Glicemia capilar (hipoglicemia é causa tratável!)\n• Gasometria\n• Eletrólitos (K+, Ca2+)\n• Considerar USG point-of-care (tamponamento, hipovolemia)" },
      { id: "differential", title: "Diagnóstico Diferencial", content: "Bradicardia grave (FC < 60 com má perfusão):\n• Hipóxia (mais comum!) → ventilar\n• Hipotermia\n• Hipoglicemia\n• Hipercalemia\n• Intoxicação (BB, BCC, digoxina)\n• Aumento de PIC\n\nRitmo chocável em criança (raro):\n• Cardiopatia congênita\n• Síndrome do QT longo\n• WPW\n• Miocardite\n• Intoxicação por tricíclicos\n• Commotio cordis\n• Hipercalemia" },
      { id: "conduct", title: "Conduta", content: "ALGORITMO PALS — PCR PEDIÁTRICA:\n\n1. Confirmar PCR: irresponsivo + sem respiração + sem pulso (< 10s)\n2. Chamar ajuda + DEA/desfibrilador\n3. Iniciar RCP de alta qualidade:\n\nCOMPRESSÕES:\n• Lactente: 2 dedos (1 socorrista) ou técnica dos 2 polegares (2 socorristas)\n• Criança: 1 ou 2 mãos (conforme tamanho)\n• Frequência: 100-120/min\n• Profundidade: ≥ 1/3 do diâmetro AP do tórax\n  — Lactente: ~4 cm\n  — Criança: ~5 cm\n• Retorno completo do tórax\n• Minimizar interrupções\n• Relação: 30:2 (1 socorrista) ou 15:2 (2 socorristas)\n• Com via aérea avançada: compressões contínuas + 1 ventilação a cada 2-3s (20-30/min)\n\n4. Conectar monitor → analisar ritmo:\n\nRITMO NÃO-CHOCÁVEL (assistolia/AESP):\n• RCP 2 min → reanalisar\n• Adrenalina 0,01 mg/kg IV/IO a cada 3-5 min\n• Buscar causas reversíveis (5H/5T)\n\nRITMO CHOCÁVEL (FV/TVSP):\n• Choque: 2 J/kg (1º) → 4 J/kg (2º) → 4-10 J/kg (subsequentes)\n• RCP 2 min após cada choque\n• Adrenalina 0,01 mg/kg a cada 3-5 min (após 2º choque)\n• Amiodarona 5 mg/kg IV/IO (após 3º choque, máx 3 doses)\n\nBRADICARDIA COM PULSO E MÁ PERFUSÃO (FC < 60):\n• Ventilar + oxigenar (muitas vezes resolve!)\n• Se persiste apesar de ventilação: RCP\n• Adrenalina 0,01 mg/kg IV/IO\n• Atropina 0,02 mg/kg IV (se tônus vagal ou BAV)\n\nVIA AÉREA:\n• BVM é aceitável durante toda a RCP\n• IOT: tubo sem cuff < 1 ano; com cuff > 1 ano\n• Tamanho do tubo: (idade/4) + 3,5 (com cuff) ou (idade/4) + 4 (sem cuff)\n• Lâmina reta para < 2 anos, curva para > 2 anos" },
      { id: "followup", title: "Acompanhamento", content: "Pós-RCE (Retorno da Circulação Espontânea):\n• Manter normoxemia (SpO2 94-99% — evitar hiperóxia!)\n• Normocapnia (ETCO2 35-45 mmHg)\n• Normotermia (36-37,5°C) ou hipotermia terapêutica (32-34°C por 48h se comatoso)\n• PA adequada para idade (vasopressores se necessário)\n• Glicemia 80-180 mg/dL\n• Tratar causa da PCR\n• UTI pediátrica\n• EEG em 24h (prognóstico neurológico)\n• Ecocardiograma\n• Comunicar família" },
      { id: "treatment", title: "Abordagem Terapêutica", content: "DOSES PEDIÁTRICAS (peso em kg):\n\nAdrenalina:\n• 0,01 mg/kg IV/IO (0,1 mL/kg da 1:10.000)\n• Máx: 1 mg/dose\n• A cada 3-5 min\n\nAmiodarona:\n• 5 mg/kg IV/IO bolus (máx 300 mg)\n• Pode repetir 2x (total 15 mg/kg)\n\nAtropina:\n• 0,02 mg/kg IV/IO (dose mín 0,1 mg, máx 0,5 mg)\n• Para bradicardia com pulso\n\nDesfibrilação:\n• 1º: 2 J/kg\n• 2º: 4 J/kg\n• Subsequentes: 4-10 J/kg (máx 10 J/kg ou dose adulta)\n\nExpansão volêmica:\n• SF 0,9% 20 mL/kg IV bolus (pode repetir)\n\nGlicose:\n• Neonato: Glicose 10% 5 mL/kg\n• Lactente: Glicose 25% 2-4 mL/kg\n• Criança: Glicose 50% 1-2 mL/kg\n\nBicarbonato de sódio:\n• 1 mEq/kg IV (apenas se acidose documentada)\n\nCálcio (gluconato 10%):\n• 0,6 mL/kg IV lento (máx 20 mL)\n• Indicação: hipocalcemia, hipercalemia, intox BCC" },
      { id: "prescriptions", title: "Guia de Prescrições", content: "PRESCRIÇÃO: PCR PEDIÁTRICA — PALS\nPeso estimado: _____ kg (Fita de Broselow se disponível)\n\n1. RCP: compressões 100-120/min + ventilação 15:2 (2 socorristas)\n2. O2 100% via BVM\n3. Acesso IV/IO\n4. Adrenalina _____ mg (0,01 mg/kg) IV/IO a cada 3-5 min\n5. Se FV/TVSP: Desfibrilação _____ J (2 J/kg → 4 J/kg → 4-10 J/kg)\n6. Se FV/TVSP refratária: Amiodarona _____ mg (5 mg/kg) IV/IO\n7. SF 0,9% _____ mL (20 mL/kg) IV bolus se hipovolemia\n8. Glicemia capilar → Glicose _____ mL IV se hipoglicemia\n9. Capnografia contínua (meta ETCO2 > 10-15)\n10. Pós-RCE: SpO2 94-99%, normocapnia, PA adequada, UTI\n11. Registrar: ritmo, choques, drogas, tempos, RCE" },
      { id: "references", title: "Referências Bibliográficas", content: "1. Topjian AA et al. AHA Pediatric Basic and Advanced Life Support Guidelines. Circulation 2020.\n2. Maconochie IK et al. ILCOR Pediatric Life Support Guidelines. Resuscitation 2020.\n3. SBP — Diretrizes de Ressuscitação Cardiopulmonar Pediátrica, 2019.\n4. PALS Provider Manual, AHA, 2020.\n5. Atkins DL et al. Pediatric Defibrillation. Circulation 2018." }
    ]
  },
  {
    id: "convulsao-febril",
    title: "Convulsão Febril",
    categoryId: "pediatric-emergency",
    sections: [
      { id: "intro", title: "Introdução", content: "A convulsão febril é a emergência neurológica mais comum na pediatria, acometendo 2-5% das crianças entre 6 meses e 5 anos. É desencadeada por febre (≥ 38°C) na ausência de infecção do SNC ou causa metabólica.\n\nApesar de assustadora para os pais, a convulsão febril simples tem prognóstico excelente, sem aumento do risco de epilepsia e sem necessidade de tratamento crônico." },
      { id: "def", title: "Definição", content: "Crise convulsiva associada a febre (≥ 38°C) em criança de 6 meses a 5 anos, sem infecção do SNC, sem distúrbio metabólico e sem história de convulsão afebril prévia.\n\nClassificação:\n\nConvulsão febril SIMPLES (70-80%):\n• Generalizada (tônico-clônica)\n• Duração < 15 minutos\n• Não recorre em 24 horas\n• Sem déficit neurológico pós-ictal\n\nConvulsão febril COMPLEXA (20-30%):\n• Focal (início em um hemicorpo)\n• Duração ≥ 15 minutos\n• Recorre em 24 horas\n• Déficit neurológico pós-ictal (paralisia de Todd)\n\nEstado de mal febril:\n• Convulsão febril com duração > 30 minutos" },
      { id: "screening", title: "Rastreamento e Identificação", content: "Fatores de risco para convulsão febril:\n• Idade: 6 meses a 5 anos (pico: 12-18 meses)\n• História familiar de convulsão febril (risco 2-3x maior)\n• Febre alta (> 39°C)\n• Velocidade de ascensão da febre (mais que o valor absoluto)\n\nFatores de risco para RECORRÊNCIA (30-40% recorrem):\n• Idade < 18 meses no primeiro episódio\n• Febre baixa (< 39°C) no primeiro episódio\n• Curta duração da febre antes da convulsão (< 1h)\n• História familiar positiva\n\nQuando investigar com PL (excluir meningite):\n• < 6 meses: PL recomendada\n• 6-12 meses: PL considerar (especialmente se não vacinada para Hib e pneumococo)\n• > 12 meses: PL se sinais meníngeos\n• Qualquer idade: se uso prévio de antibiótico (mascara meningite)" },
      { id: "etiology", title: "Etiologia", content: "Causas de febre mais comuns associadas:\n• IVAS (infecção viral de vias aéreas superiores) — mais frequente\n• Otite média aguda\n• Roséola (HHV-6) — clássica associação com convulsão febril\n• Infecção urinária\n• Gastroenterite\n• Vacinação (24h após DTP, 7-10 dias após MMR)\n• Pneumonia\n\nFisiopatologia:\n• Imaturidade do SNC (limiar convulsivo mais baixo)\n• Susceptibilidade genética (herança complexa/poligênica)\n• Febre → liberação de citocinas → excitabilidade neuronal\n• A rapidez da elevação térmica parece mais importante que o valor absoluto" },
      { id: "clinical", title: "Apresentação Clínica", content: "Convulsão febril simples (típica):\n• Criança com febre (geralmente > 39°C)\n• Crise tônico-clônica generalizada\n• Duração: geralmente 1-3 minutos (< 15 min)\n• Período pós-ictal breve (sonolência por 30-60 min)\n• Exame neurológico PÓS-ICTAL: normal\n\nConvulsão febril complexa:\n• Início focal (um lado do corpo)\n• Duração prolongada (≥ 15 min)\n• Múltiplos episódios em 24h\n• Déficit neurológico pós-ictal (paralisia de Todd)\n\nSinais de ALERTA (NÃO é convulsão febril simples):\n• Idade < 6 meses ou > 5 anos\n• Sem febre\n• Rigidez de nuca, fontanela abaulada\n• Petéquias/púrpura\n• Déficit neurológico persistente\n• Convulsão > 30 min (estado de mal)" },
      { id: "diagnosis", title: "Diagnóstico", content: "O diagnóstico é CLÍNICO! Exames são para EXCLUIR causas.\n\nConvulsão febril SIMPLES (criança > 12 meses, bem, sem sinais meníngeos):\n• Nenhum exame é obrigatório\n• Investigar FOCO DA FEBRE (não a convulsão)\n\nExames a considerar:\n• Glicemia capilar (sempre — excluir hipoglicemia)\n• Hemograma, PCR (avaliar infecção)\n• Eletrólitos (Na+, Ca2+, Mg2+ — se vômitos/diarreia)\n• EAS + urocultura (se sem foco febril aparente)\n• Hemocultura (se toxêmico)\n\nPunção lombar:\n• Indicação: suspeita de meningite (rigidez de nuca, fontanela abaulada, toxemia)\n• < 6 meses: considerar sempre\n• 6-12 meses: considerar se vacinação incompleta\n• > 12 meses: apenas se sinais meníngeos\n\nEEG:\n• NÃO indicado na convulsão febril simples\n• Considerar na complexa (especialmente se focal ou recorrente)\n\nNeuroimagem (TC/RM):\n• NÃO indicada na convulsão febril simples\n• Considerar na complexa com déficit focal persistente" },
      { id: "differential", title: "Diagnóstico Diferencial", content: "Convulsão com febre em criança:\n• Convulsão febril (simples ou complexa)\n• Meningite bacteriana\n• Encefalite viral (HSV!)\n• Epilepsia com febre como gatilho\n• Intoxicação\n• Distúrbio eletrolítico (hiponatremia, hipocalcemia)\n• Malária cerebral (áreas endêmicas)\n• Abscesso cerebral\n\nEventos que simulam convulsão:\n• Calafrios da febre (tremores rítmicos — param com contenção)\n• Síncope febril\n• Espasmo do choro (cianótico ou pálido)" },
      { id: "conduct", title: "Conduta", content: "CRISE EM CURSO (se ainda convulsionando à chegada):\n\n1. Proteger via aérea: posição lateral, aspirar secreções\n2. O2 sob máscara se SpO2 < 94%\n3. NÃO introduzir objetos na boca!\n4. Glicemia capilar (tratar hipoglicemia)\n5. Se crise > 5 min:\n   • Diazepam 0,3-0,5 mg/kg IV lento (máx 10 mg) OU\n   • Diazepam 0,5 mg/kg VR (máx 10 mg — se sem acesso IV) OU\n   • Midazolam 0,2 mg/kg IM/IN (máx 5 mg)\n6. Se persiste após 5 min: repetir BZD (1x)\n7. Se refratária: Fenitoína 20 mg/kg IV em 20 min OU Fenobarbital 20 mg/kg IV\n\nCRISE JÁ CESSOU (maioria dos casos):\n\n1. Avaliar ABC\n2. Monitorizar: SpO2, FC, FR, temperatura\n3. Antitérmico: Dipirona 10-15 mg/kg IV OU Paracetamol 15 mg/kg VO\n4. Investigar e tratar o FOCO DA FEBRE\n5. Observar por 2-4h\n6. Orientar pais\n\nCONVULSÃO FEBRIL COMPLEXA:\n• Observação mais prolongada (6-12h)\n• Considerar PL\n• Considerar EEG ambulatorial\n• Avaliação neuropediátrica" },
      { id: "followup", title: "Acompanhamento", content: "Convulsão febril SIMPLES:\n• Alta após 2-4h de observação se bem\n• NÃO há indicação de anticonvulsivante profilático\n• NÃO há indicação de EEG ou neuroimagem\n• Tratar febre (conforto, não previne recorrência)\n• Risco de recorrência: ~30%\n\nOrientações aos pais:\n• Convulsão febril NÃO causa dano cerebral\n• NÃO aumenta risco de epilepsia (simples: 1-2%, igual população geral)\n• Se nova crise: posição lateral, não colocar nada na boca, cronometrar, chamar emergência se > 5 min\n• Não é necessário manter a criança afebril continuamente\n\nConvulsão febril COMPLEXA:\n• Encaminhar para neuropediatria\n• EEG ambulatorial\n• Acompanhamento mais próximo\n• Risco de epilepsia: 4-6%\n\nProfilaxia contínua (RARA indicação):\n• Considerar apenas se recorrências muito frequentes (> 3/ano) + impacto na qualidade de vida\n• Diazepam 0,33 mg/kg/dose VO 8/8h durante febre (profilaxia intermitente)" },
      { id: "treatment", title: "Abordagem Terapêutica", content: "Anticonvulsivantes para crise aguda:\n\nDiazepam:\n• IV: 0,3-0,5 mg/kg (máx 10 mg) — lento em 2-3 min\n• VR: 0,5 mg/kg (máx 10 mg) — se sem acesso IV\n• Início: 1-3 min IV, 5-10 min VR\n\nMidazolam:\n• IM: 0,2 mg/kg (máx 5 mg)\n• IN (intranasal): 0,2 mg/kg (máx 5 mg)\n• Bucal: 0,2 mg/kg\n• Vantagem: não precisa de acesso IV\n\nSe refratária:\n• Fenitoína 20 mg/kg IV em 20 min (máx 1g)\n  — Diluir em SF (precipita em SG!)\n  — Monitorizar ECG (risco de arritmia)\n• OU Fenobarbital 20 mg/kg IV em 10-15 min\n  — Depressão respiratória (ter BVM pronto)\n\nAntitérmicos (para conforto, NÃO previnem convulsão):\n• Dipirona 10-15 mg/kg IV/VO 6/6h\n• Paracetamol 10-15 mg/kg VO 6/6h\n• Ibuprofeno 5-10 mg/kg VO 6-8/8h (> 6 meses)" },
      { id: "prescriptions", title: "Guia de Prescrições", content: "PRESCRIÇÃO: CONVULSÃO FEBRIL — EMERGÊNCIA\nPeso: _____ kg | Idade: _____ meses/anos\n\nSE CRISE EM CURSO:\n1. O2 sob máscara se SpO2 < 94%\n2. Glicemia capilar\n3. Diazepam _____ mg IV lento (0,3 mg/kg) OU\n   Diazepam _____ mg VR (0,5 mg/kg) OU\n   Midazolam _____ mg IM/IN (0,2 mg/kg)\n4. Se persiste > 5 min: repetir BZD 1x\n5. Se refratária: Fenitoína _____ mg IV em 20 min (20 mg/kg)\n\nCRISE CESSOU:\n6. Dipirona _____ mg IV (10-15 mg/kg) OU Paracetamol _____ mg VO (15 mg/kg)\n7. Investigar foco febril\n8. Observação por 2-4h\n9. Alta com orientações se bem\n10. Registrar: tipo de crise, duração, temperatura, drogas, dose" },
      { id: "references", title: "Referências Bibliográficas", content: "1. AAP — Febrile Seizures: Clinical Practice Guideline. Pediatrics 2011.\n2. Steering Committee on Quality Improvement — Febrile Seizures. Pediatrics 2008.\n3. Shinnar S, Glauser TA. Febrile Seizures. J Child Neurol 2002.\n4. SBP — Consenso sobre Convulsão Febril, 2019.\n5. Graves RC et al. Febrile Seizures: Risks, Evaluation, and Prognosis. Am Fam Physician 2012." }
    ]
  },
  {
    id: "bronquiolite-grave",
    title: "Bronquiolite Grave",
    categoryId: "pediatric-emergency",
    sections: [
      { id: "intro", title: "Introdução", content: "A bronquiolite viral aguda (BVA) é a principal causa de internação em lactentes < 1 ano. É causada principalmente pelo vírus sincicial respiratório (VSR). A doença é autolimitada na maioria dos casos, mas pode ser grave em prematuros, cardiopatas e imunodeprimidos.\n\nO tratamento é SUPORTIVO — não há evidência para uso de broncodilatadores, corticoides ou antibióticos na bronquiolite clássica." },
      { id: "def", title: "Definição", content: "Infecção viral do trato respiratório inferior que causa inflamação, edema e obstrução dos bronquíolos em crianças < 2 anos (geralmente < 12 meses) no primeiro episódio de sibilância.\n\nAgente etiológico:\n• VSR (Vírus Sincicial Respiratório): 50-80% dos casos\n• Rinovírus: segundo mais comum\n• Metapneumovírus humano\n• Parainfluenza, influenza, adenovírus\n• Bocavírus\n\nEpidemiologia:\n• Pico: outono e inverno (março-julho no Brasil)\n• Idade: 2-6 meses (pico de gravidade)\n• Quase todas as crianças são infectadas pelo VSR até os 2 anos\n• Transmissão: gotículas e fômites (sobrevive 6h em superfícies)" },
      { id: "screening", title: "Rastreamento e Identificação", content: "Critérios de gravidade (indicação de internação):\n• SpO2 < 92% persistente\n• Frequência respiratória > 70 irpm\n• Apneia (especialmente em < 2 meses e prematuros)\n• Recusa alimentar (ingestão < 50% do habitual)\n• Desidratação\n• Letargia ou irritabilidade acentuada\n• Tiragem intensa (subcostal, intercostal, supraesternal)\n\nFatores de risco para bronquiolite grave:\n• Prematuridade (< 37 semanas, especialmente < 32 sem)\n• Idade < 3 meses\n• Cardiopatia congênita com repercussão hemodinâmica\n• Displasia broncopulmonar\n• Imunodeficiência\n• Doença neuromuscular\n• Síndrome de Down" },
      { id: "etiology", title: "Etiologia", content: "Fisiopatologia:\n• Vírus → infecta epitélio bronquiolar → inflamação + necrose + edema\n• Produção excessiva de muco\n• Obstrução bronquiolar (parcial → air trapping; completa → atelectasia)\n• Não há broncoespasmo significativo (bronquíolos imaturos, pouca musculatura lisa)\n  — Por isso broncodilatadores NÃO funcionam!\n\nEvolução natural:\n• Fase catarral (1-3 dias): coriza, tosse, febre baixa\n• Fase de estado (3-7 dias): sibilância, taquipneia, desconforto respiratório\n• Recuperação (7-14 dias)\n• Tosse pode persistir por 2-4 semanas\n• Pico de gravidade: dia 3-5 da doença" },
      { id: "clinical", title: "Apresentação Clínica", content: "Início (fase catarral):\n• Coriza hialina\n• Espirros\n• Tosse\n• Febre baixa (< 39°C, nem sempre presente)\n\nProgressão (desconforto respiratório):\n• Taquipneia (FR > 60 em < 2 meses, > 50 em 2-12 meses)\n• Sibilância (nem sempre presente nos mais graves!)\n• Estertores crepitantes difusos\n• Tiragem subcostal, intercostal, supraesternal\n• Batimento de asa nasal\n• Gemência (sinal de gravidade em lactentes!)\n• Recusa alimentar\n• Irritabilidade → letargia (sinal de falência)\n\nBronquiolite GRAVE:\n• SpO2 < 90%\n• FR > 70\n• Apneia\n• Cianose\n• Exaustão respiratória (tórax silencioso — sinal ominoso!)\n• Necessidade de suporte ventilatório" },
      { id: "diagnosis", title: "Diagnóstico", content: "Diagnóstico é CLÍNICO! (Primeiro episódio de sibilância em lactente com quadro viral.)\n\nExames complementares — indicados apenas em casos graves ou atípicos:\n• SpO2 (OBRIGATÓRIO — guia internação)\n• Pesquisa de antígeno viral nasal ou PCR (VSR) — epidemiologia, não muda conduta\n• Gasometria: se insuficiência respiratória (pCO2 > 50 = gravidade)\n• RX tórax: NÃO é rotina! Indicar se:\n  — Dúvida diagnóstica\n  — Piora inesperada\n  — Suspeita de complicação (pneumonia, atelectasia, pneumotórax)\n  — RX típico: hiperinsuflação, retificação de arcos costais, atelectasia\n• Hemograma, PCR: apenas se suspeita de infecção bacteriana secundária\n\n⚠️ NÃO solicitar RX de rotina — aumenta uso desnecessário de antibióticos!" },
      { id: "differential", title: "Diagnóstico Diferencial", content: "Sibilância em lactente:\n• Bronquiolite viral aguda\n• Asma do lactente (episódios recorrentes, > 3 episódios)\n• Pneumonia bacteriana\n• Aspiração de corpo estranho\n• Refluxo gastroesofágico com aspiração\n• Insuficiência cardíaca (cardiopatia congênita)\n• Fibrose cística\n• Anel vascular\n• Coqueluche (tosse paroxística, < 3 meses)\n• Laringomalácia / traqueomalácia" },
      { id: "conduct", title: "Conduta", content: "TRATAMENTO É SUPORTIVO! \"Less is more.\"\n\nMEDIDAS EFICAZES:\n1. Oxigenoterapia:\n   • Se SpO2 < 92% persistente\n   • Cateter nasal 0,5-2 L/min\n   • Meta: SpO2 ≥ 92%\n\n2. Cânula nasal de alto fluxo (CNAF):\n   • Fluxo: 2 L/kg/min (máx 8 L/min em < 12 kg)\n   • FiO2: titular para SpO2 ≥ 92%\n   • Reduz trabalho respiratório, gera CPAP\n   • Primeira linha em muitos protocolos para bronquiolite moderada-grave\n\n3. Hidratação:\n   • Via oral preferencial (oferecer fracionado)\n   • Se recusa oral (< 50%): SNG ou IV\n   • SF 0,9% IV de manutenção (Holliday-Segar com cautela — risco de SIADH)\n   • Monitorizar Na+ (hiponatremia por SIADH é comum!)\n\n4. Aspiração nasal:\n   • SF 0,9% nasal + aspiração gentil\n   • Antes das mamadas e antes de avaliar SpO2\n\n5. Posicionamento:\n   • Cabeceira elevada 30°\n   • Decúbito dorsal (prevenção de morte súbita)\n\nMEDIDAS QUE NÃO FUNCIONAM (NÃO USAR!):\n❌ Beta-2 agonista (salbutamol) — sem benefício, efeitos adversos\n❌ Adrenalina inalatória — sem benefício sustentado\n❌ Corticoide sistêmico ou inalatório — sem benefício\n❌ Antibióticos (sem infecção bacteriana secundária)\n❌ Fisioterapia respiratória de rotina\n❌ Nebulização com solução salina hipertônica (evidência fraca, controversa)\n\nINDICAÇÃO DE UTI:\n• Apneia recorrente\n• SpO2 < 90% apesar de O2/CNAF\n• Exaustão respiratória\n• Necessidade de VNI (CPAP) ou VM\n• pCO2 > 60 mmHg" },
      { id: "followup", title: "Acompanhamento", content: "Critérios de alta hospitalar:\n• SpO2 > 92% em ar ambiente por > 4h (incluindo sono)\n• FR adequada para idade\n• Sem tiragem significativa\n• Aceitando ≥ 75% da alimentação habitual\n• Sem apneia por > 24h\n• Pais orientados\n\nOrientações de alta:\n• Doença tem pico no dia 3-5 e melhora gradual em 7-14 dias\n• Tosse pode persistir 2-4 semanas\n• Sinais de alerta: piora da respiração, recusa alimentar, cianose, apneia\n• Lavagem nasal com SF frequente\n• Evitar tabagismo passivo\n• Retorno se piora\n\nPrevenção:\n• Palivizumabe (anticorpo monoclonal anti-VSR): prematuros < 29 sem, cardiopatas, DBP\n  — Dose: 15 mg/kg IM mensal na sazonalidade\n• Nirsevimabe: dose única, nova opção para todos RN/lactentes\n• Higiene das mãos (medida mais importante!)" },
      { id: "treatment", title: "Abordagem Terapêutica", content: "RESUMO — O que FUNCIONA:\n• O2 se SpO2 < 92%\n• CNAF (alto fluxo nasal)\n• Hidratação (oral > SNG > IV)\n• Aspiração nasal com SF\n\nCNAF (Cânula Nasal de Alto Fluxo):\n• Fluxo: 2 L/kg/min\n• Umidificado e aquecido (37°C)\n• FiO2: iniciar 40%, titular\n• Avaliação em 1-2h: se sem melhora → VNI/UTI\n\nVNI (CPAP nasal):\n• CPAP 5-8 cmH2O\n• Se falha de CNAF\n• Monitorizar em UTI\n\nVM invasiva:\n• Se falha de VNI, apneia refratária, exaustão\n• VC 6-8 mL/kg, FR baixa, TE prolongado\n• Cautela com hiperinsuflação\n\nHidratação IV (se necessária):\n• SF 0,9% + SG 5% na proporção de Holliday-Segar\n• Restringir para 2/3 da manutenção (risco de SIADH)\n• Monitorizar Na+ a cada 12-24h\n\n⚠️ Teste terapêutico com broncodilatador: pode ser tentado 1x em > 6 meses com sibilância. Se sem resposta objetiva → suspender." },
      { id: "prescriptions", title: "Guia de Prescrições", content: "PRESCRIÇÃO: BRONQUIOLITE GRAVE — INTERNAÇÃO\nPeso: _____ kg | Idade: _____ meses\n\n1. Dieta: aleitamento materno / fórmula fracionada VO. Se recusa: SNG\n2. O2 sob cateter nasal _____ L/min (manter SpO2 ≥ 92%) OU\n   CNAF _____ L/min (2 L/kg/min), FiO2 ____%\n3. SF 0,9% nasal 0,5-1 mL em cada narina + aspiração gentil antes das mamadas e SN\n4. Cabeceira elevada 30°\n5. HV: SF 0,9% + SG 5% IV _____ mL/h (2/3 da manutenção Holliday-Segar)\n6. Monitorização contínua: SpO2, FC, FR\n7. Na+ sérico a cada 24h (vigiar SIADH)\n8. Dipirona _____ mg IV 6/6h se T ≥ 37,8°C (10-15 mg/kg)\n9. Reavaliar a cada 4-6h: FR, tiragem, SpO2, aceitação oral\n10. Se piora (SpO2 < 90%, apneia, exaustão): chamar UTI\n11. ❌ NÃO USAR: salbutamol, corticoide, antibiótico (sem indicação)" },
      { id: "references", title: "Referências Bibliográficas", content: "1. AAP — Clinical Practice Guideline: Bronchiolitis. Pediatrics 2014 (reafirmada 2023).\n2. Ralston SL et al. Updated Clinical Practice Guideline: Bronchiolitis. Pediatrics 2023.\n3. SBP — Diretriz de Bronquiolite Viral Aguda, 2020.\n4. Franklin D et al. A Randomized Trial of High-Flow Oxygen Therapy in Infants with Bronchiolitis (PARIS trial). N Engl J Med 2018.\n5. Florin TA et al. Viral Bronchiolitis. Lancet 2017." }
    ]
  },
  {
    id: "asma-grave-pediatrica",
    title: "Asma Grave Pediátrica",
    categoryId: "pediatric-emergency",
    sections: [
      { id: "intro", title: "Introdução", content: "A crise asmática grave é uma emergência respiratória frequente na pediatria. Diferente da bronquiolite, na asma há broncoespasmo verdadeiro com resposta a broncodilatadores.\n\nO manejo escalonado com beta-2 agonista inalatório, brometo de ipratrópio, corticoide sistêmico precoce e sulfato de magnésio em casos graves reduz significativamente a necessidade de intubação e internação em UTI." },
      { id: "def", title: "Definição", content: "Exacerbação aguda de asma com obstrução significativa do fluxo aéreo, não responsiva ao tratamento broncodilatador inicial convencional, com risco de insuficiência respiratória.\n\nCritérios de asma em pediatria:\n• > 3 episódios de sibilância em < 2 anos OU\n• Sibilância em criança > 2 anos com fatores de risco (atopia, eczema, rinite)\n\nClassificação da gravidade da crise:\n\nLeve:\n• Fala frases completas, consegue deitar\n• FR levemente aumentada\n• SpO2 > 95%\n• PFE > 50% do previsto\n\nModerada:\n• Frases incompletas, prefere sentar\n• Tiragem subcostal\n• SpO2 92-95%\n• PFE 30-50%\n\nGrave:\n• Palavras isoladas, agitado\n• Tiragem universal, uso de musculatura acessória\n• SpO2 < 92%\n• PFE < 30%\n\nQuase fatal (iminência de PCR):\n• Sonolento, confuso\n• Tórax silencioso\n• Bradicardia\n• Cianose" },
      { id: "screening", title: "Rastreamento e Identificação", content: "Fatores de risco para crise fatal:\n• Internação prévia em UTI por asma\n• Intubação prévia por asma\n• ≥ 2 internações ou ≥ 3 idas ao PS no último ano\n• Uso de ≥ 2 frascos de beta-2 de resgate/mês\n• Uso recente de corticoide oral\n• Não uso de corticoide inalatório\n• Comorbidades: alergia alimentar, doença psiquiátrica\n• Baixa adesão ao tratamento\n• Tabagismo passivo" },
      { id: "etiology", title: "Etiologia", content: "Desencadeantes da crise:\n• Infecções virais (principal em < 5 anos — rinovírus, VSR)\n• Alérgenos (ácaros, mofo, pelo de animais, pólen)\n• Mudança climática\n• Exercício físico\n• Poluição / tabagismo passivo\n• IVAS\n• Estresse emocional\n• Suspensão do tratamento de manutenção\n• AINEs / AAS (em sensibilizados)\n\nFisiopatologia da crise:\n• Broncoespasmo (contração da musculatura lisa)\n• Edema de mucosa brônquica\n• Hipersecreção de muco\n• Obstrução → air trapping → hiperinsuflação → ↑ trabalho respiratório" },
      { id: "clinical", title: "Apresentação Clínica", content: "Crise leve-moderada:\n• Dispneia\n• Sibilância expiratória (audível)\n• Tosse seca\n• Taquipneia\n• Tiragem subcostal\n• Pode falar frases\n• SpO2 > 92%\n\nCrise grave:\n• Dispneia intensa, fala palavras isoladas\n• Agitação, ansiedade\n• Uso intenso de musculatura acessória\n• Tiragem universal (subcostal + intercostal + supraesternal)\n• Sibilância bilateral intensa\n• Taquicardia > 130\n• SpO2 < 92%\n• Pulso paradoxal > 20 mmHg\n\nQuase fatal (iminência de PCR):\n• Sonolência, confusão (hipercapnia)\n• Tórax silencioso (obstrução tão grave que não há fluxo!)\n• Bradicardia\n• Cianose\n• Movimentos paradoxais do tórax/abdome\n\n⚠️ \"Tórax silencioso\" em criança em crise = GRAVIDADE EXTREMA!" },
      { id: "diagnosis", title: "Diagnóstico", content: "Diagnóstico clínico!\n\nExames na emergência:\n• SpO2 (OBRIGATÓRIO)\n• PFE (pico de fluxo expiratório) — se > 6 anos e cooperativa\n  — > 50%: leve\n  — 30-50%: moderada\n  — < 30%: grave\n• Gasometria: se crise grave (SpO2 < 92%)\n  — Normal: pCO2 baixa (hiperventilação compensatória)\n  — pCO2 normal ou alta = sinal de gravidade (fadiga/exaustão)\n  — Acidose respiratória = iminência de PCR\n\nRX tórax — NÃO é rotina! Indicar se:\n• Primeiro episódio de sibilância\n• Suspeita de complicação (pneumotórax, pneumonia)\n• Resposta pobre ao tratamento\n• Assimetria de ausculta" },
      { id: "differential", title: "Diagnóstico Diferencial", content: "Sibilância em criança:\n• Asma\n• Bronquiolite (< 2 anos, primeiro episódio)\n• Corpo estranho (início súbito, assimétrico)\n• Pneumonia\n• Crupe (estridor inspiratório)\n• Anafilaxia (urticária, angioedema)\n• Insuficiência cardíaca\n• Fibrose cística\n• Traqueomalácia / broncomalácia" },
      { id: "conduct", title: "Conduta", content: "TRATAMENTO ESCALONADO DA CRISE GRAVE:\n\n1. O2: manter SpO2 ≥ 94%\n2. BETA-2 AGONISTA (PRIMEIRA LINHA):\n   • Salbutamol spray + espaçador:\n     — 1 jato/3 kg (mín 3, máx 10 jatos)\n     — A cada 20 min por 1h (3 doses)\n   • OU Salbutamol nebulização:\n     — 0,15 mg/kg/dose (mín 2,5 mg, máx 5 mg) em SF 3 mL\n     — A cada 20 min por 1h\n   • Crise grave: pode ser contínuo (0,5 mg/kg/h, máx 15 mg/h)\n\n3. BROMETO DE IPRATRÓPIO (associar na crise moderada-grave):\n   • Spray: 3-4 jatos (60-80 mcg) com espaçador\n   • OU Nebulização: 250 mcg (< 5 anos) ou 500 mcg (> 5 anos)\n   • A cada 20 min por 1h (apenas nas primeiras 3 doses)\n\n4. CORTICOIDE SISTÊMICO (PRECOCE!):\n   • Prednisolona 1-2 mg/kg VO (máx 40-60 mg) — preferida se tolera VO\n   • OU Metilprednisolona 1-2 mg/kg IV (máx 60 mg)\n   • OU Dexametasona 0,3-0,6 mg/kg VO/IV (máx 16 mg) — dose única ou 2 dias\n   • Manter por 3-5 dias\n\n5. SULFATO DE MAGNÉSIO (crise grave refratária):\n   • 25-75 mg/kg IV em 20-30 min (máx 2 g)\n   • Dose única\n   • Broncodilatador independente de beta-2\n   • Monitorizar PA (hipotensão)\n\n6. AMINOFILINA IV (último recurso antes de IOT):\n   • Dose de ataque: 5-6 mg/kg IV em 20 min\n   • Manutenção: 0,5-1 mg/kg/h IV BIC\n   • UTI obrigatória (janela terapêutica estreita)\n\n7. ADRENALINA IM (se suspeita de anafilaxia associada):\n   • 0,01 mg/kg IM (máx 0,3 mg criança)\n\n8. VNI / IOT:\n   • VNI (BiPAP): antes de IOT, se cooperativa\n   • IOT: apenas se iminência de PCR\n   • Ketamina é o indutor de escolha (broncodilatador)\n   • Ventilação com TE prolongado, FR baixa (evitar air trapping)" },
      { id: "followup", title: "Acompanhamento", content: "Pós-crise na emergência:\n• Reavaliar 1h após tratamento inicial\n• Se boa resposta (SpO2 > 94%, sem tiragem, fala frases): observar 1-2h → alta\n• Se resposta parcial: manter tratamento, reavaliar em 4h\n• Se sem resposta: internar\n\nAlta da emergência:\n• Prednisolona 1-2 mg/kg/dia VO por 3-5 dias\n• Salbutamol spray de resgate 4/4-6/6h por 5-7 dias\n• Iniciar ou otimizar corticoide inalatório\n• Plano de ação para crise por escrito\n• Retorno em 48-72h ou se piora\n\nInternação:\n• Manter beta-2 a cada 1-4h conforme resposta\n• Corticoide sistêmico até melhora clínica\n• Desmame do O2\n• Alta quando: SpO2 > 94% em AA, sem tiragem, beta-2 ≥ 4/4h" },
      { id: "treatment", title: "Abordagem Terapêutica", content: "Doses pediátricas — Resumo:\n\nSalbutamol spray (100 mcg/jato):\n• 1 jato/3 kg a cada 20 min (3 doses) → depois 1-4h\n\nSalbutamol nebulização:\n• 0,15 mg/kg/dose (mín 2,5 mg) + SF 3 mL a cada 20 min\n\nIpratrópio nebulização:\n• < 5 anos: 250 mcg | > 5 anos: 500 mcg (apenas 3 doses)\n\nPrednisolona VO:\n• 1-2 mg/kg/dia (máx 40-60 mg) por 3-5 dias\n\nDexametasona:\n• 0,3-0,6 mg/kg VO/IV (máx 16 mg) — dose única ou 2 dias\n• Vantagem: melhor adesão, menos vômitos\n\nMgSO4 50% IV:\n• 25-75 mg/kg em 20-30 min (máx 2 g)\n\nAdrenalina (se anafilaxia):\n• 0,01 mg/kg IM (1:1000) — máx 0,3 mg\n\nKetamina (se IOT necessária):\n• 1-2 mg/kg IV — broncodilatador, ideal para asmático" },
      { id: "prescriptions", title: "Guia de Prescrições", content: "PRESCRIÇÃO: ASMA GRAVE PEDIÁTRICA — EMERGÊNCIA\nPeso: _____ kg | Idade: _____ anos\n\n1. O2 para SpO2 ≥ 94%\n2. Salbutamol spray _____ jatos (1j/3kg) + espaçador a cada 20 min × 3\n3. Ipratrópio spray 3-4 jatos + espaçador a cada 20 min × 3 (junto com salbutamol)\n4. Prednisolona _____ mg VO (1-2 mg/kg) OU Dexametasona _____ mg VO (0,6 mg/kg)\n5. Se grave refratária: MgSO4 50% _____ mg (50 mg/kg) + SF 50 mL IV em 20 min\n6. Reavaliar em 1h: FR, SpO2, tiragem, ausculta\n7. Se boa resposta: Salbutamol spray 4/4-6/6h\n8. Se resposta parcial: manter 1/1h, internar\n9. Se quase fatal: UTI + considerar aminofilina IV / VNI / IOT\n10. Alta: Prednisolona _____ mg/dia VO por 3-5 dias + spray de resgate + CI\n11. Registrar: gravidade, SpO2, PFE, drogas, doses, resposta" },
      { id: "references", title: "Referências Bibliográficas", content: "1. GINA — Global Strategy for Asthma Management and Prevention, 2024.\n2. SBP/SBPT — Diretrizes de Manejo da Asma. J Bras Pneumol 2023.\n3. BTS/SIGN — British Guideline on the Management of Asthma, 2019.\n4. Rowe BH et al. Magnesium Sulfate for Acute Asthma. Cochrane Database Syst Rev 2000.\n5. Castro-Rodriguez JA et al. Dexamethasone Compared with Prednisolone for Acute Asthma in Children. J Pediatr 2015." }
    ]
  },
  {
    id: "desidratacao-grave-pediatrica",
    title: "Desidratação Grave Pediátrica",
    categoryId: "pediatric-emergency",
    sections: [
      { id: "intro", title: "Introdução", content: "A desidratação grave é uma emergência pediátrica frequente, sendo a gastroenterite aguda (diarreia + vômitos) a principal causa. A doença diarreica aguda ainda é causa significativa de morbimortalidade em crianças < 5 anos no Brasil.\n\nA terapia de reidratação oral (TRO) é o pilar do tratamento na maioria dos casos. A reidratação IV é reservada para desidratação grave ou choque." },
      { id: "def", title: "Definição", content: "Perda de água e eletrólitos corporal com comprometimento hemodinâmico e/ou metabólico.\n\nClassificação (OMS/MS):\n\nSem desidratação:\n• Sem sinais de desidratação\n• Perda < 3% do peso\n\nDesidratação (algum grau):\n• Sede intensa, olhos encovados\n• Sinal da prega: lento\n• Irritabilidade\n• Perda 3-9% do peso\n\nDesidratação GRAVE:\n• Letargia ou inconsciência\n• Olhos muito encovados\n• Sinal da prega: muito lento (> 2s)\n• Bebe mal ou não consegue beber\n• Pulsos fracos ou ausentes\n• TEC > 5 segundos\n• Perda ≥ 10% do peso\n\nClassificação por tipo:\n• Isotônica (Na 130-150): mais comum (80%)\n• Hipotônica (Na < 130): risco de convulsão na correção\n• Hipertônica (Na > 150): risco de edema cerebral na correção → corrigir lentamente!" },
      { id: "screening", title: "Rastreamento e Identificação", content: "Avaliação clínica — sinais de gravidade:\n\n| Sinal | Alguma desidratação | Grave |\n|-------|-------------------|-------|\n| Estado geral | Irritado | Letárgico/inconsciente |\n| Olhos | Encovados | Muito encovados |\n| Lágrimas | Diminuídas | Ausentes |\n| Boca/língua | Secas | Muito secas |\n| Sede | Bebe avidamente | Bebe mal/não consegue |\n| Prega cutânea | Lenta (< 2s) | Muito lenta (> 2s) |\n| Fontanela | Deprimida | Muito deprimida |\n| Diurese | Reduzida | Ausente há > 6-8h |\n| TEC | 3-5 s | > 5 s |\n| Pulsos | Normais | Fracos/impalpáveis |\n\nEstimativa de perda:\n• Peso atual vs peso prévio recente (melhor método)\n• Se peso prévio desconhecido: usar sinais clínicos" },
      { id: "etiology", title: "Etiologia", content: "Causas de desidratação em crianças:\n\nDiarreia (mais comum):\n• Rotavírus (principal em < 5 anos)\n• Norovírus\n• E. coli enterotoxigênica\n• Salmonella, Shigella\n• Cólera (em áreas endêmicas)\n\nVômitos:\n• Gastroenterite\n• Estenose hipertrófica do piloro (< 2 meses)\n• Intussuscepção\n• Obstrução intestinal\n\nPerdas aumentadas:\n• Febre alta prolongada\n• Queimaduras\n• Cetoacidose diabética\n• Diabetes insipidus\n• Fibrose cística (sudorese excessiva)\n\nRedução da ingesta:\n• Estomatite herpética\n• Faringoamigdalite\n• Recusa alimentar em qualquer infecção" },
      { id: "clinical", title: "Apresentação Clínica", content: "Desidratação leve (3-5%):\n• Sede\n• Mucosas levemente secas\n• Diurese levemente reduzida\n• Bom estado geral\n\nDesidratação moderada (6-9%):\n• Irritabilidade\n• Olhos encovados\n• Fontanela deprimida (lactentes)\n• Mucosas secas\n• Prega cutânea lenta\n• Taquicardia\n• Oligúria\n• TEC 3-5 s\n\nDesidratação GRAVE (≥ 10%) — EMERGÊNCIA:\n• Letargia ou inconsciência\n• Olhos muito encovados, sem lágrimas\n• Mucosas muito secas\n• Prega cutânea muito lenta (> 2s)\n• Fontanela muito deprimida\n• Taquicardia intensa\n• Pulsos fracos ou filiformes\n• Hipotensão (sinal TARDIO em crianças!)\n• TEC > 5 s\n• Extremidades frias, moteadas\n• Anúria\n• Acidose metabólica (respiração de Kussmaul)" },
      { id: "diagnosis", title: "Diagnóstico", content: "Diagnóstico CLÍNICO! Exames complementares na desidratação grave:\n\n1. Eletrólitos: Na+, K+, Cl- (classificar tipo de desidratação)\n2. Gasometria venosa: acidose metabólica (AG normal = perda de bicarbonato)\n3. Ureia e creatinina (relação ureia/creatinina > 20 = pré-renal)\n4. Glicemia capilar (hipoglicemia em lactentes!)\n5. Hemograma (hemoconcentração)\n6. EAS (densidade urinária alta > 1.020 = concentração)\n\nDesidratação hipernatrêmica (Na > 150):\n⚠️ ATENÇÃO ESPECIAL:\n• Pele \"pastosa\" (não enrugada como na isotônica)\n• Irritabilidade > letargia\n• Convulsão (tanto na desidratação quanto na correção rápida)\n• Corrigir lentamente: Na não deve cair > 10-12 mEq/L em 24h\n• Se corrigir rápido → edema cerebral → herniação" },
      { id: "differential", title: "Diagnóstico Diferencial", content: "Choque em criança:\n• Desidratação grave (hipovolêmico)\n• Choque séptico\n• Choque cardiogênico (miocardite, cardiopatia)\n• Choque anafilático\n• Choque hemorrágico (trauma)\n\nLetargia em lactente:\n• Desidratação grave\n• Meningite / sepse\n• Hipoglicemia\n• Intussuscepção (choro intermitente + fezes em geleia)\n• Intoxicação\n• Traumatismo craniano (maus-tratos)" },
      { id: "conduct", title: "Conduta", content: "PLANO C — DESIDRATAÇÃO GRAVE (OMS/MS):\n\n1. Fase de EXPANSÃO (rápida):\n   • SF 0,9% 20 mL/kg IV em bolus rápido (20-30 min)\n   • Reavaliar após cada bolus\n   • Repetir até 3x (total 60 mL/kg) se necessário\n   • Se após 60 mL/kg sem melhora: pensar em choque séptico ou cardíaco\n\n2. Fase de REPOSIÇÃO (4h):\n   • Após estabilização hemodinâmica\n   • Repor déficit estimado:\n     — Leve: 30-50 mL/kg em 4h\n     — Moderada: 50-100 mL/kg em 4h\n     — Grave: 100 mL/kg em 4h\n   • Soro: SF 0,9% ou SG 5% + NaCl 20% (conforme Na sérico)\n\n3. Fase de MANUTENÇÃO:\n   • Holliday-Segar:\n     — Até 10 kg: 100 mL/kg/dia\n     — 10-20 kg: 1000 mL + 50 mL/kg acima de 10 kg\n     — > 20 kg: 1500 mL + 20 mL/kg acima de 20 kg\n   • Adicionar perdas contínuas (diarreia: 10 mL/kg por evacuação)\n\n4. Correção de eletrólitos:\n   • K+: repor após diurese (KCl 10% 1-2 mEq/kg/dia)\n   • Na: correção lenta se hipernatremia (máx 10-12 mEq/L/24h)\n   • Bicarbonato: geralmente corrige com hidratação (não repor de rotina)\n\n5. REIDRATAÇÃO ORAL (TRO) — assim que possível:\n   • SRO (sais de reidratação oral — OMS): 75 mL/kg em 4h\n   • Oferecer em pequenos volumes frequentes (colher/seringa)\n   • Se vomitar: esperar 10 min e retornar\n\n6. ALIMENTAÇÃO:\n   • Manter aleitamento materno (NUNCA suspender!)\n   • Realimentar precocemente (4-6h após início da reidratação)\n   • Dieta habitual para idade (sem restrição)" },
      { id: "followup", title: "Acompanhamento", content: "• Peso a cada 6-12h (melhor parâmetro de reidratação)\n• Monitorizar: diurese (meta > 1 mL/kg/h), turgor, fontanela\n• Na+ e K+ a cada 6-12h se IV\n• Glicemia a cada 6h em lactentes\n• Transição IV → VO assim que tolerado\n\nCritérios de alta:\n• Hidratado clinicamente\n• Tolerando VO adequadamente\n• Diurese normal\n• Sem vômitos\n• Melhora da diarreia (tendência)\n\nOrientações:\n• SRO após cada evacuação líquida (50-100 mL < 2 anos; 100-200 mL > 2 anos)\n• Manter alimentação habitual\n• Sinais de alerta: recusa de líquidos, vômitos persistentes, sangue nas fezes, febre alta, prostração\n• Retorno em 24-48h ou se piora\n\nZinco (OMS): 10 mg/dia (< 6 meses) ou 20 mg/dia (> 6 meses) por 10-14 dias" },
      { id: "treatment", title: "Abordagem Terapêutica", content: "Soluções:\n• SF 0,9%: expansão (20 mL/kg em bolus)\n• SG 5% + NaCl 20%: manutenção e reposição\n• SRO (OMS): Na 75 mEq/L, glicose 75 mmol/L, osmolaridade 245 mOsm/L\n\nAntiemético (se vômitos impedem TRO):\n• Ondansetrona 0,15 mg/kg IV/VO (máx 4 mg) — dose única\n• Permite sucesso da TRO em até 80% dos casos!\n\nNÃO USAR:\n❌ Antidiarreicos (loperamida) — contraindicados em crianças\n❌ Probióticos: evidência limitada, não são rotina\n❌ Antibióticos de rotina (apenas se disenteria bacteriana ou cólera)\n\nAntibiótico (se indicado):\n• Disenteria (fezes com sangue + febre):\n  — Ciprofloxacino 15 mg/kg/dose VO 12/12h por 3 dias OU\n  — Ceftriaxona 50-100 mg/kg/dia IV/IM 1x/dia por 3 dias\n• Cólera: Azitromicina 20 mg/kg VO dose única\n\nDesidratação hipernatrêmica (Na > 150):\n• Corrigir em 48-72h (não rápido!)\n• SF 0,9% para expansão (isotônico é seguro)\n• Solução hipotônica (SF 0,45%) para correção lenta\n• Queda máxima de Na: 10-12 mEq/L em 24h\n• Na+ sérico a cada 4-6h" },
      { id: "prescriptions", title: "Guia de Prescrições", content: "PRESCRIÇÃO: DESIDRATAÇÃO GRAVE — PLANO C\nPeso: _____ kg | Idade: _____ meses/anos\n\nFASE DE EXPANSÃO:\n1. SF 0,9% _____ mL (20 mL/kg) IV em bolus (20-30 min)\n2. Reavaliar: se ainda desidratado → repetir SF 20 mL/kg (até 3x)\n3. Glicemia capilar → se < 60: Glicose 10% 5 mL/kg IV\n\nFASE DE REPOSIÇÃO (após estabilização):\n4. SF 0,9% + SG 5% _____ mL IV em 4h (50-100 mL/kg)\n5. Monitorizar Na+ e K+ a cada 6h\n6. KCl 10% _____ mL em cada 500 mL de soro (após diurese — 1-2 mEq/kg/dia)\n\nFASE DE MANUTENÇÃO:\n7. HV Holliday-Segar: _____ mL/dia\n8. Repor perdas: 10 mL/kg por evacuação líquida\n\nSUPORTE:\n9. Dieta: aleitamento materno + realimentar em 4-6h\n10. SRO entre as mamadas assim que tolerar VO\n11. Ondansetrona _____ mg IV (0,15 mg/kg) se vômitos\n12. Zinco 10-20 mg/dia VO por 10-14 dias\n13. Peso 12/12h, diurese horária\n14. Registrar: peso, grau de desidratação, Na+, volume infundido" },
      { id: "references", title: "Referências Bibliográficas", content: "1. OMS — The Treatment of Diarrhoea: A Manual for Physicians and Other Senior Health Workers, 2005.\n2. MS/Brasil — Manejo do Paciente com Diarreia, 2019.\n3. SBP — Guia Prático de Atualização: Diarreia Aguda, 2021.\n4. Freedman SB et al. Oral Ondansetron for Gastroenteritis in a Pediatric Emergency Department. N Engl J Med 2006.\n5. Guarino A et al. ESPGHAN/ESPID Guidelines for the Management of Acute Gastroenteritis in Children. JPGN 2014." }
    ]
  },
  {
    id: "sepse-neonatal",
    title: "Sepse Neonatal",
    categoryId: "pediatric-emergency",
    sections: [
      { id: "intro", title: "Introdução", content: "A sepse neonatal é uma emergência com alta morbimortalidade no período neonatal (0-28 dias). Divide-se em precoce (< 72h de vida — transmissão vertical) e tardia (> 72h — nosocomial ou comunitária).\n\nO RN tem imaturidade imunológica, apresentação clínica inespecífica e deterioração rápida. A suspeita clínica deve ter baixo limiar para início empírico de antibioticoterapia." },
      { id: "def", title: "Definição", content: "Síndrome clínica de infecção sistêmica no período neonatal (0-28 dias de vida).\n\nSepse neonatal PRECOCE (< 72h):\n• Transmissão vertical (materno-fetal)\n• Agentes: Streptococcus do grupo B (GBS), E. coli, Listeria monocytogenes\n• Fatores de risco: RPM > 18h, corioamnionite, prematuridade, febre materna intraparto, colonização materna por GBS sem profilaxia\n\nSepse neonatal TARDIA (> 72h):\n• Nosocomial (UTI neonatal) ou comunitária\n• Agentes nosocomiais: Staphylococcus coagulase-negativo (mais comum), S. aureus, Klebsiella, Pseudomonas, Candida\n• Agentes comunitários: E. coli, GBS, S. aureus\n• Fatores de risco: prematuridade, cateter central, VM prolongada, NPT, cirurgia" },
      { id: "screening", title: "Rastreamento e Identificação", content: "⚠️ SINAIS SUTIS! O RN não manifesta infecção como criança/adulto.\n\n\"O RN não lê o livro\" — qualquer alteração pode ser sepse:\n• \"Não está bem\" (impressão da equipe/mãe)\n• Instabilidade térmica (febre OU hipotermia — hipotermia é mais comum no prematuro!)\n• Recusa alimentar / resíduo gástrico\n• Letargia OU irritabilidade\n• Taquipneia / apneia / gemência\n• Taquicardia OU bradicardia\n• Icterícia de início precoce\n• Distensão abdominal\n• Hipoglicemia ou hiperglicemia\n\nCritérios de sepse neonatal (adaptados):\n• Suspeita clínica + ≥ 2 sinais de SIRS neonatal:\n  — T > 38,5°C ou < 36°C\n  — FC > 180 ou < 100 bpm\n  — FR > 60 ou necessidade de VM\n  — Leucócitos > 34.000 ou < 5.000 ou > 10% bastões" },
      { id: "etiology", title: "Etiologia", content: "Sepse PRECOCE (< 72h):\n• Streptococcus grupo B (GBS / S. agalactiae): 40-50%\n  — Profilaxia intraparto com penicilina reduz risco em 80%\n• E. coli: 20-30% (especialmente em prematuros)\n• Listeria monocytogenes: rara, mas grave\n• Outros: Klebsiella, Enterococcus, H. influenzae\n\nSepse TARDIA (> 72h):\nNosocomial:\n• Staphylococcus coagulase-negativo (mais comum em UTIN)\n• S. aureus (MRSA possível)\n• Klebsiella, Pseudomonas, Acinetobacter\n• Candida (especialmente em < 1500g, uso prolongado de ATB)\n\nComunitária:\n• E. coli\n• GBS (tardio — pode causar meningite)\n• S. aureus\n\nMeningite neonatal:\n• GBS e E. coli: 60-70% dos casos\n• Sempre considerar PL na suspeita de sepse neonatal!" },
      { id: "clinical", title: "Apresentação Clínica", content: "SINAIS INESPECÍFICOS (qualquer um pode ser sepse!):\n\nGeral:\n• \"Não parece bem\"\n• Instabilidade térmica (hipo > hipertermia em prematuros)\n• Letargia, hipotonia\n• Irritabilidade\n\nRespiratório:\n• Taquipneia, gemência\n• Apneia (especialmente em prematuros)\n• Desconforto respiratório\n• Necessidade de aumento de O2/suporte\n\nCardiovascular:\n• Taquicardia persistente\n• Bradicardia (sinal de gravidade)\n• Perfusão periférica ruim (TEC > 3s)\n• Hipotensão (sinal tardio)\n\nGastrointestinal:\n• Recusa alimentar\n• Vômitos, resíduo gástrico\n• Distensão abdominal\n• Enterocolite necrosante (NEC)\n\nNeurológico:\n• Convulsões\n• Fontanela abaulada\n• Hipotonia / hipertonia\n\nHematológico:\n• Petéquias, púrpura\n• Sangramento (CIVD)\n• Icterícia" },
      { id: "diagnosis", title: "Diagnóstico", content: "TRIAGEM SÉPTICA (colher ANTES do ATB!):\n\n1. Hemoculturas (2 amostras de sítios diferentes) — padrão-ouro\n2. Hemograma completo com contagem diferencial:\n   — Leucócitos < 5.000 ou > 25.000 (≤ 72h) ou > 15.000 (> 72h)\n   — Relação I/T (imaturos/total) > 0,2\n   — Plaquetopenia < 100.000\n3. PCR quantitativa (seriada — 0h e 24-48h)\n4. Procalcitonina (se disponível — melhor marcador precoce)\n5. Punção lombar (LCR):\n   — Sempre na sepse tardia\n   — Sepse precoce: se hemocultura positiva, convulsão, ou criança instável\n   — LCR neonatal normal: até 25-30 céls/mm³ (! diferente do adulto)\n6. Urocultura (sonda vesical — especialmente sepse tardia)\n7. Gasometria + lactato\n8. Glicemia\n9. Coagulograma (CIVD)\n10. Função renal e hepática\n\n⚠️ NÃO esperar resultados para iniciar ATB! Iniciar IMEDIATAMENTE após coleta." },
      { id: "differential", title: "Diagnóstico Diferencial", content: "RN com desconforto respiratório:\n• Sepse neonatal\n• Doença de membrana hialina (prematuro)\n• Taquipneia transitória do RN\n• Pneumonia congênita\n• Cardiopatia congênita\n• Hérnia diafragmática\n\nRN com instabilidade térmica + letargia:\n• Sepse\n• Distúrbio metabólico (hipoglicemia, erros inatos)\n• Hemorragia intracraniana\n• Cardiopatia\n• Hipotireoidismo congênito\n\nRN com convulsão:\n• Sepse / meningite\n• Hipoglicemia\n• Hipocalcemia\n• Encefalopatia hipóxico-isquêmica\n• Hemorragia intracraniana\n• Erros inatos do metabolismo" },
      { id: "conduct", title: "Conduta", content: "EMERGÊNCIA — iniciar em até 1 hora!\n\n1. ESTABILIZAÇÃO:\n• Monitorização contínua: SpO2, FC, FR, PA, temperatura\n• Acesso venoso (idealmente 2)\n• Se choque: SF 0,9% 10-20 mL/kg IV em 10-20 min (mais cauteloso que em crianças maiores!)\n  — Reavaliar após cada bolus\n  — Máx 40-60 mL/kg na 1ª hora (risco de sobrecarga em prematuros)\n• O2 / suporte ventilatório conforme necessidade\n• Glicemia: manter > 45 mg/dL (Glicose 10% 2-4 mL/kg IV se hipo)\n• Temperatura: manter 36,5-37,5°C (berço aquecido)\n\n2. ANTIBIOTICOTERAPIA EMPÍRICA:\n\nSEPSE PRECOCE (< 72h):\n• Ampicilina 50 mg/kg/dose IV 12/12h (< 7 dias) ou 8/8h (> 7 dias)\n  + Gentamicina 4-5 mg/kg/dose IV 1x/dia\n• Se meningite: Ampicilina 100 mg/kg/dose + Gentamicina\n  (ou substituir Gentamicina por Cefotaxima 50 mg/kg/dose 8/8h)\n\nSEPSE TARDIA (> 72h):\nComunitária:\n• Ampicilina + Gentamicina (mesmo esquema)\nNosocomial:\n• Oxacilina 50 mg/kg/dose IV 6/6h + Amicacina 15 mg/kg/dose IV 1x/dia\n  OU Vancomicina 15 mg/kg/dose IV 8/12h + Cefepime 50 mg/kg/dose IV 8/8h\n  (conforme perfil microbiológico local)\n\nSe Candida suspeita (prematuro < 1500g, ATB prolongado):\n• Anfotericina B 1 mg/kg/dia IV OU Fluconazol 12 mg/kg/dose\n\n3. SUPORTE HEMODINÂMICO:\n• Se hipotensão refratária a volume:\n  — Dopamina 5-20 mcg/kg/min IV BIC → se refratário:\n  — Adrenalina 0,05-0,3 mcg/kg/min IV BIC OU\n  — Noradrenalina 0,05-0,5 mcg/kg/min IV BIC\n  — Hidrocortisona 1-2 mg/kg IV se choque refratário a catecolaminas (insuficiência adrenal)" },
      { id: "followup", title: "Acompanhamento", content: "• Hemoculturas de controle em 48-72h\n• PCR seriada (queda = boa resposta)\n• Hemograma seriado\n• Ajustar ATB conforme cultura e antibiograma\n\nDuração do ATB:\n• Sepse sem foco, hemocultura negativa, PCR normalizada: 5-7 dias\n• Sepse com hemocultura positiva: 10-14 dias\n• Meningite por GBS: 14-21 dias\n• Meningite por Gram-negativo: 21 dias\n• Osteomielite: 4-6 semanas\n\nSuspender ATB precocemente se:\n• Hemocultura negativa em 48-72h\n• PCR normal seriada\n• Clinicamente bem\n• Triagem séptica normal\n\nComplicações a monitorizar:\n• Meningite (PL de controle)\n• CIVD\n• NEC (distensão abdominal, sangue nas fezes)\n• Insuficiência renal\n• Sequelas neurológicas (follow-up com neuropediatra)" },
      { id: "treatment", title: "Abordagem Terapêutica", content: "DOSES NEONATAIS DE ANTIBIÓTICOS:\n\nAmpicilina:\n• Sepse: 50 mg/kg/dose IV\n• Meningite: 100 mg/kg/dose IV\n• < 7 dias: 12/12h | > 7 dias: 8/8h\n\nGentamicina:\n• 4-5 mg/kg/dose IV 1x/dia (≥ 35 sem)\n• 4 mg/kg/dose IV a cada 36h (< 35 sem)\n• Monitorizar nível sérico\n\nCefotaxima:\n• 50 mg/kg/dose IV 8/8h (meningite)\n\nVancomicina:\n• 15 mg/kg/dose IV 8/8h (> 35 sem) ou 12/12h (< 35 sem)\n\nOxacilina:\n• 50 mg/kg/dose IV 6/6h\n\nAmicacina:\n• 15 mg/kg/dose IV 1x/dia\n\nDrogas vasoativas:\n• Dopamina: 5-20 mcg/kg/min IV BIC\n• Adrenalina: 0,05-0,3 mcg/kg/min IV BIC\n• Noradrenalina: 0,05-0,5 mcg/kg/min IV BIC\n• Hidrocortisona: 1-2 mg/kg IV 8/8h (choque refratário)" },
      { id: "prescriptions", title: "Guia de Prescrições", content: "PRESCRIÇÃO: SEPSE NEONATAL PRECOCE\nPeso: _____ g | IG: _____ semanas | Horas de vida: _____\n\n1. Monitorização contínua: FC, FR, SpO2, PA, T\n2. Incubadora / berço aquecido (manter T 36,5-37,5°C)\n3. Dieta zero → iniciar dieta enteral assim que possível\n4. HV: TIG _____ mg/kg/min (iniciar 4-6 mg/kg/min)\n5. COLHER ANTES DO ATB: hemoculturas (2), hemograma, PCR, glicemia, gasometria\n6. PL se indicada\n7. Ampicilina _____ mg IV ___/___h (50 mg/kg/dose)\n8. Gentamicina _____ mg IV 1x/dia (4-5 mg/kg/dose)\n9. Se choque: SF 0,9% _____ mL (10-20 mL/kg) IV em 10-20 min\n10. Se hipotensão refratária: Dopamina _____ mcg/kg/min IV BIC\n11. Glicemia capilar 6/6h (manter > 45 mg/dL)\n12. Hemoculturas de controle em 48-72h\n13. PCR em 24-48h\n14. Registrar: fatores de risco maternos, sinais clínicos, ATB, hora de início" },
      { id: "references", title: "Referências Bibliográficas", content: "1. Shane AL et al. Neonatal Sepsis. Lancet 2017.\n2. Puopolo KM et al. AAP — Management of Neonates Born at ≥ 35 Weeks' Gestation with Suspected or Proven Early-Onset Bacterial Sepsis. Pediatrics 2018.\n3. SBP — Diretrizes de Sepse Neonatal, 2022.\n4. Simonsen KA et al. Early-Onset Neonatal Sepsis. Clin Microbiol Rev 2014.\n5. Procianoy RS, Silveira RC. The Challenges of Neonatal Sepsis Management. J Pediatr (Rio J) 2020." }
    ]
  },
  {
    id: "meningite-pediatrica",
    title: "Meningite Pediátrica",
    categoryId: "pediatric-emergency",
    sections: [
      { id: "intro", title: "Introdução", content: "A meningite bacteriana permanece uma emergência pediátrica com mortalidade de 5-10% e sequelas neurológicas em até 30% dos sobreviventes. O diagnóstico e tratamento precoces são fundamentais.\n\nA vacinação contra Haemophilus influenzae tipo b (Hib), pneumococo e meningococo reduziu drasticamente a incidência, mas a doença ainda ocorre, especialmente em lactentes jovens e não vacinados." },
      { id: "def", title: "Definição", content: "Inflamação das meninges (pia-máter e aracnoide) causada por infecção, geralmente bacteriana ou viral, em paciente pediátrico.\n\nAgentes por faixa etária:\n\nNeonato (0-28 dias):\n• Streptococcus grupo B (GBS)\n• E. coli\n• Listeria monocytogenes\n\nLactente (1-3 meses):\n• GBS, E. coli\n• S. pneumoniae\n• N. meningitidis\n• Listeria\n\nCriança (3 meses-18 anos):\n• Neisseria meningitidis (meningococo) — mais comum em crianças\n• Streptococcus pneumoniae (pneumococo)\n• Haemophilus influenzae tipo b (raro após vacinação)\n\nMeningite viral:\n• Enterovírus (mais comum)\n• HSV (neonatos!)\n• Arbovírus" },
      { id: "screening", title: "Rastreamento e Identificação", content: "SINAIS CLÁSSICOS (crianças maiores):\n• Febre alta + cefaleia + rigidez de nuca\n• Sinal de Kernig, sinal de Brudzinski\n• Fotofobia\n\nLACTENTES — sinais ATÍPICOS (meningismo pode estar AUSENTE!):\n• Irritabilidade paradoxal (chora MAIS quando pega no colo)\n• Fontanela abaulada e tensa\n• Recusa alimentar\n• Letargia ou irritabilidade\n• Convulsão febril (sempre considerar meningite!)\n• Vômitos\n• Febre OU hipotermia\n• Gemência\n\n⚠️ Em < 12 meses, rigidez de nuca pode estar AUSENTE!\n\nSinais de ALERTA para meningococcemia:\n• Petéquias/púrpura (progressão rápida!)\n• Choque séptico fulminante\n• CIVD\n• Necrose de extremidades" },
      { id: "etiology", title: "Etiologia", content: "Meningite BACTERIANA:\n\n• N. meningitidis (meningococo):\n  — Sorotipos B e C mais comuns no Brasil\n  — Pode causar meningococcemia fulminante (púrpura + choque)\n  — Transmissão: gotículas respiratórias\n  — Doença de notificação compulsória\n\n• S. pneumoniae (pneumococo):\n  — Maior mortalidade (até 20%)\n  — Maior taxa de sequelas (surdez, déficit cognitivo)\n  — Vacinação PCV13/PCV15 reduziu incidência\n\n• H. influenzae tipo b:\n  — Praticamente eliminada pela vacinação\n  — Ainda ocorre em não vacinados\n\nMeningite VIRAL:\n• Geralmente benigna e autolimitada\n• Enterovírus é o agente mais comum\n• HSV-2 neonatal: EMERGÊNCIA — Aciclovir imediato!\n\nMeningite TUBERCULOSA:\n• Evolução subaguda (semanas)\n• LCR: linfocítico, glicose baixa, proteína alta, ADA elevada" },
      { id: "clinical", title: "Apresentação Clínica", content: "Criança > 2 anos (apresentação clássica):\n• Febre alta (> 39°C)\n• Cefaleia intensa\n• Vômitos em jato\n• Rigidez de nuca\n• Fotofobia\n• Sinal de Kernig (+)\n• Sinal de Brudzinski (+)\n• Letargia → coma\n• Convulsões (20-30%)\n\nLactente < 12 meses (apresentação atípica):\n• Febre (pode estar ausente no neonato)\n• Irritabilidade paradoxal\n• Choro inconsolável / gemência\n• Fontanela abaulada\n• Recusa alimentar\n• Letargia ou hipotonia\n• Convulsão\n• Apneia (neonatos)\n• Opistótono (sinal tardio)\n\nMeningococcemia:\n• Petéquias que NÃO desaparecem à digitopressão\n• Púrpura rapidamente progressiva\n• Choque séptico fulminante (horas!)\n• CIVD\n• Síndrome de Waterhouse-Friderichsen (hemorragia adrenal bilateral)" },
      { id: "diagnosis", title: "Diagnóstico", content: "PUNÇÃO LOMBAR — padrão-ouro:\n\n| Parâmetro | Normal | Bacteriana | Viral |\n|-----------|--------|-----------|-------|\n| Aspecto | Límpido | Turvo/purulento | Límpido |\n| Células | < 10 (< 30 em neonatos) | > 1000 (PMN) | 10-500 (linfo) |\n| Glicose | > 2/3 sérica | < 40 mg/dL | Normal |\n| Proteína | < 40 (< 150 em neonatos) | > 100 | 50-100 |\n| Lactato | < 3,5 | > 3,5 | < 3,5 |\n\nExames do LCR:\n• Celularidade total e diferencial\n• Bioquímica: glicose (+ glicemia simultânea!), proteína, lactato\n• Gram + cultura (mais importante!)\n• Aglutinação em látex (meningococo, pneumococo, Hib, GBS)\n• PCR viral (se disponível)\n\nTC antes da PL? NÃO é rotina em crianças! Fazer se:\n• Déficit neurológico focal\n• Papiledema\n• GCS < 13\n• Convulsão prolongada\n• Imunossupressão\n\n⚠️ NÃO atrasar ATB pela PL! Coletar hemocultura → iniciar ATB → depois PL.\n\nOutros exames:\n• Hemocultura (2 amostras)\n• Hemograma, PCR, procalcitonina\n• Eletrólitos (Na+ — risco de SIADH)\n• Coagulograma (CIVD se meningococcemia)\n• Glicemia" },
      { id: "differential", title: "Diagnóstico Diferencial", content: "Febre + rigidez de nuca em criança:\n• Meningite bacteriana\n• Meningite viral\n• Encefalite\n• Abscesso cerebral\n• Meningite tuberculosa\n\nFebre + petéquias em criança:\n• Meningococcemia (emergência!)\n• Endocardite infecciosa\n• Púrpura trombocitopênica idiopática (PTI) — sem febre\n• Vasculite (Henoch-Schönlein)\n• Infecção viral com plaquetopenia\n\nConvulsão febril vs meningite:\n• Convulsão febril simples: exame neurológico pós-ictal normal, sem meningismo\n• Meningite: sinais meníngeos, alteração persistente de consciência" },
      { id: "conduct", title: "Conduta", content: "EMERGÊNCIA — ATB em até 30-60 minutos!\n\n1. ESTABILIZAÇÃO:\n• ABC + monitorização\n• Acesso venoso\n• Se choque: SF 0,9% 20 mL/kg IV bolus\n• O2 se SpO2 < 94%\n\n2. COLETAR EXAMES (NÃO atrasar ATB!):\n• Hemoculturas (2)\n• Se estável: PL\n• Se instável: hemocultura → ATB → estabilizar → PL depois\n\n3. DEXAMETASONA (ANTES ou JUNTO com ATB!):\n• 0,15 mg/kg IV 6/6h por 2-4 dias\n• Iniciar ANTES ou até 30 min após 1ª dose de ATB\n• Benefício comprovado: reduz surdez (principalmente por Hib e pneumococo)\n• Se meningococo: benefício controverso, mas geralmente administrada\n\n4. ANTIBIOTICOTERAPIA EMPÍRICA:\n\nNeonato (< 28 dias):\n• Ampicilina 100 mg/kg/dose IV 8/8h + Cefotaxima 50 mg/kg/dose IV 8/8h\n  (OU Ampicilina + Gentamicina)\n• Se suspeita de HSV: Aciclovir 20 mg/kg/dose IV 8/8h\n\nLactente 1-3 meses:\n• Ceftriaxona 100 mg/kg/dia IV (máx 4g) 1x/dia OU 12/12h\n  + Ampicilina 100 mg/kg/dose IV 6/6h (cobertura de Listeria)\n\nCriança > 3 meses:\n• Ceftriaxona 100 mg/kg/dia IV (máx 4g) 1x/dia ou 12/12h\n• Se suspeita de pneumococo resistente: + Vancomicina 15 mg/kg/dose IV 6/6h\n\n5. SUPORTE:\n• Restrição hídrica para 2/3 da manutenção (risco de SIADH)\n• Monitorizar Na+ a cada 6-12h\n• Anticonvulsivante se convulsão\n• Cabeceira elevada 30°" },
      { id: "followup", title: "Acompanhamento", content: "• PL de controle em 48-72h se Gram-negativo ou resposta lenta\n• PCR e hemograma seriados\n• Na+ a cada 12-24h (SIADH)\n\nDuração do ATB:\n• N. meningitidis: 7 dias\n• S. pneumoniae: 10-14 dias\n• H. influenzae: 7-10 dias\n• GBS: 14-21 dias\n• Gram-negativos: 21 dias\n• Listeria: 21 dias\n\nProfilaxia de contatos (meningococo):\n• Rifampicina 10 mg/kg/dose 12/12h por 2 dias (crianças)\n  OU Ceftriaxona 250 mg IM dose única (< 15 anos)\n  OU Ciprofloxacino 500 mg VO dose única (adultos)\n• Contactantes domiciliares e íntimos (< 1 metro por > 4h nos últimos 7 dias)\n\nProfilaxia de contatos (Hib):\n• Rifampicina 20 mg/kg/dia 1x/dia por 4 dias (se contactante < 4 anos não vacinado)\n\nSequelas a monitorizar:\n• Surdez neurossensorial (audiometria antes da alta e 1 mês)\n• Déficit cognitivo\n• Hidrocefalia\n• Déficit motor\n• Epilepsia\n\nNotificação compulsória (SINAN) — OBRIGATÓRIA" },
      { id: "treatment", title: "Abordagem Terapêutica", content: "DOSES PEDIÁTRICAS DE ATB PARA MENINGITE:\n\nCeftriaxona:\n• 100 mg/kg/dia IV (máx 4g) — 1x/dia ou dividido 12/12h\n• ⚠️ Não usar em neonatos < 28 dias (risco de kernicterus e precipitação com cálcio)\n\nCefotaxima:\n• 200 mg/kg/dia IV dividido 6/6h (alternativa no neonato)\n\nAmpicilina:\n• Sepse: 50 mg/kg/dose | Meningite: 100 mg/kg/dose IV\n\nVancomicina:\n• 15 mg/kg/dose IV 6/6h (pneumococo resistente)\n• Monitorizar nível sérico\n\nAciclovir:\n• 20 mg/kg/dose IV 8/8h (HSV neonatal — 21 dias)\n\nDexametasona:\n• 0,15 mg/kg/dose IV 6/6h × 2-4 dias\n• ANTES ou junto com 1ª dose de ATB\n\nAnticonvulsivante:\n• Fenobarbital 20 mg/kg IV (neonatos)\n• Diazepam 0,3 mg/kg IV ou Midazolam 0,2 mg/kg IM (crianças)\n\nManitol (se sinais de HIC):\n• 0,25-1 g/kg IV em 20 min" },
      { id: "prescriptions", title: "Guia de Prescrições", content: "PRESCRIÇÃO: MENINGITE BACTERIANA PEDIÁTRICA (> 3 meses)\nPeso: _____ kg | Idade: _____ meses/anos\n\n1. Monitorização contínua: FC, FR, SpO2, PA, GCS\n2. Acesso venoso calibroso\n3. COLHER: hemoculturas (2), PL (celularidade, bioquímica, Gram, cultura, látex)\n4. Dexametasona _____ mg IV (0,15 mg/kg) — ANTES do ATB!\n5. Ceftriaxona _____ mg IV 12/12h (100 mg/kg/dia, máx 4g)\n6. Se suspeita de pneumococo resistente: + Vancomicina _____ mg IV 6/6h (15 mg/kg/dose)\n7. Dexametasona _____ mg IV 6/6h por 2-4 dias\n8. HV: SF + SG a 2/3 da manutenção (risco de SIADH)\n9. Na+ sérico a cada 12h\n10. Dipirona _____ mg IV 6/6h se febre\n11. Se convulsão: Diazepam _____ mg IV (0,3 mg/kg)\n12. Cabeceira 30°\n13. Notificação SINAN IMEDIATA\n14. Quimioprofilaxia de contatos (se meningococo)\n15. Audiometria antes da alta\n16. Registrar: LCR (aspecto, celularidade, Gram), ATB, hora de início" },
      { id: "references", title: "Referências Bibliográficas", content: "1. van de Beek D et al. Community-Acquired Bacterial Meningitis. Lancet 2016.\n2. AAP — Red Book: Report of the Committee on Infectious Diseases, 2021.\n3. MS/Brasil — Guia de Vigilância em Saúde: Meningites, 2022.\n4. SBP — Meningite Bacteriana na Infância, 2020.\n5. Tunkel AR et al. IDSA Practice Guidelines for Bacterial Meningitis. Clin Infect Dis 2004.\n6. Brouwer MC et al. Corticosteroids for Acute Bacterial Meningitis. Cochrane Database Syst Rev 2015." }
    ]
  }
];
